const express = require('express');
const { randomUUID } = require('node:crypto');
const app = express();

express.use(express.json());

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ ok: true });
});

// Project routes
require('./modules/projects/routes')(app);
require('./modules/members/routes')(app);
require('./modules/tasks/routes')(app);

module.exports = app;

function sendError(res, status, code, message) {
  res.status(status).json({ error: { code, message } });
}

exports.sendError = sendError;

const { sendError } = require('../../lib/errors');

module.exports = (app) => {
  app.post('/projects/:projectId/tasks/:taskId/comments', (req, res) => {
    const { message } = req.body;
    if (!message) return sendError(res, 400, 'BadRequest', 'Message is required');
    // Logic to save comment
    res.status(201).json({ comment: { message } });
  });
};

const { sendError } = require('../../lib/errors');

module.exports = (app) => {
  app.post('/projects/:projectId/members', (req, res) => {
    const { userId, role } = req.body;
    if (!userId || !role) return sendError(res, 400, 'BadRequest', 'User ID and role are required');
    // Logic to add member
    res.status(201).json({ member: { userId, role } });
  });
};

const { sendError } = require('../../lib/errors');

module.exports = (app) => {
  app.post('/projects', (req, res) => {
    const { name } = req.body;
    if (!name) return sendError(res, 400, 'BadRequest', 'Name is required');
    // Logic to create project
    res.status(201).json({ project: { name } });
  });
};

const { sendError } = require('../../lib/errors');

module.exports = (app) => {
  app.post('/projects/:projectId/tasks', (req, res) => {
    const { title, description } = req.body;
    if (!title || !description) return sendError(res, 400, 'BadRequest', 'Title and description are required');
    // Logic to create task
    res.status(201).json({ task: { title, description, status: 'todo' } });
  });
};

const app = require('./app');
const port = process.env.PORT || 3000;

module.exports = app;
